 69→// ─── Blacklist Check ──────────────────────────────────────────────────────────
 70→
 71→/**
 72→ * ISC #3: Check if a company is blacklisted. Returns reason if blacklisted.
 73→ * Blacklisted companies are NEVER applied to under any circumstances.
 74→ */
 75→function checkBlacklist(
 76→  company: string,
 77→  targetCompanies: TargetCompanies
 78→): { blacklisted: boolean; reason?: string } {
 79→  const companyLower = company.toLowerCase();
 80→  const blacklistEntry = targetCompanies.blacklist.find((entry) => {
 81→    const entryLower = entry.name.toLowerCase();
 82→    return companyLower.includes(entryLower) || entryLower.includes(companyLower);
 83→  });
 84→
 85→  if (blacklistEntry) {
 86→    return { blacklisted: true, reason: blacklistEntry.reason };
 87→  }
 88→
 89→  return { blacklisted: false };
 90→}
