127→// ─── Apply to Single Job ───────────────────────────────────────────────────────
128→
129→async function applyToJob(
130→  job: ScanResult | { title: string; company: string; url: string; match_score: number; location?: string },
131→  profile: MasterProfile,
132→  targetCompanies: TargetCompanies,
133→  dryRun: boolean,
134→  headless: boolean,
135→  verbose = false,
136→  force = false
137→): Promise<{ success: boolean; reason?: string; application?: ApplicationRecord }> {
138→  const location = "location" in job ? (job.location ?? "Remote") : "Remote";
139→
140→  // ISC #3: Blacklist check — NEVER apply to blacklisted companies
141→  const blacklistCheck = checkBlacklist(job.company, targetCompanies);
142→  if (blacklistCheck.blacklisted) {
143→    return {
144→      success: false,
145→      reason: `Company blacklisted: ${blacklistCheck.reason ?? job.company}`,
146→    };
147→  }
148→
149→  // ATS domain check — skip domains with repeated failures
150→  const atsCheck = isAtsDomainBlocked(job.url);
151→  if (atsCheck.blocked) {
152→    return {
153→      success: false,
154→      reason: `ATS domain "${atsCheck.domain}" temporarily blocked due to repeated failures`,
155→    };
156→  }
157→
158→  // ISC #4: Cross-workflow dedup check (bypassed with --force for testing)
159→  if (force) {
160→    console.warn(`[--force] Bypassing dedup check for ${job.company} — ${job.title}`);
161→  } else {
162→    const dedupHash = computeDedupHash(job.company, job.title, location);
163→    const dupResult = await checkDuplicate(dedupHash, STATE_PATHS.applications, job.url);
164→    if (dupResult.is_duplicate) {
165→      const existing = dupResult.existing_application;
166→      return {
167→        success: false,
168→        reason: `Already applied via ${existing?.workflow ?? "unknown workflow"} on ${existing?.timestamp?.slice(0, 10) ?? "unknown date"}`,
169→      };
170→    }
171→
172→    // Check for CAPTCHA-blocked previous attempts (non-retryable even though status is "failed")
173→    const allRecords = readApplications();
174→    const normalizedJobUrl = job.url.replace(/\/$/, "").toLowerCase();
175→    const captchaBlocked = allRecords.find(r =>
176→      r.notes?.includes("[CAPTCHA_BLOCKED]") &&
177→      (r.dedup_hash === dedupHash ||
178→        (r.url && r.url.replace(/\/$/, "").toLowerCase() === normalizedJobUrl))
179→    );
180→    if (captchaBlocked) {
181→      return {
182→        success: false,
183→        reason: "Previously blocked by CAPTCHA — not retrying",
184→      };
185→    }
186→  }
187→
188→  // Pre-flight URL validation — catch expired listings before launching browser
189→  try {
190→    const headResp = await fetch(job.url, { method: "HEAD", redirect: "follow", signal: AbortSignal.timeout(10_000) });
191→    const finalUrl = headResp.url.toLowerCase();
192→    if (headResp.status === 404 || headResp.status === 410) {
193→      return { success: false, reason: `Job listing expired (HTTP ${headResp.status})` };
194→    }
195→    // Detect redirects to search/home pages (common for expired listings)
196→    if (
197→      (finalUrl.includes("/search") || finalUrl.includes("/jobs?") || finalUrl.endsWith("/jobs") || finalUrl.endsWith("/careers")) &&
198→      !job.url.toLowerCase().includes("/search")
199→    ) {
200→      return { success: false, reason: `Job listing expired (redirected to ${new URL(headResp.url).pathname})` };
201→    }
202→  } catch {
203→    // Network errors on HEAD don't block — browser may still work
204→  }
205→
206→  // ISC #8: Select resume PDF path based on job title (unified via browser-submit.ts)
207→  const resume = await selectResumePath(job.title, profile.profile);
208→  if (!resume || !existsSync(resume.path)) {
209→    return {
210→      success: false,
211→      reason: `No resume PDF found for role "${job.title}"${resume ? ` (path: ${resume.path})` : ""}`,
212→    };
213→  }
214→  const resumeVariant = resume.key;
215→
216→  const record = buildApplicationRecord(job, resumeVariant, location);
217→
218→  // Submit via browser automation (AI form fill primary, static adapter fallback)
219→  const submitResult = await submitApplication({
220→    url: job.url,
221→    profile: profile.profile,
222→    fullProfile: profile,
223→    resumePath: resume.path,
224→    headless,
225→    verbose,
226→    dryRun,
227→    job: {
228→      title: job.title,
229→      company: job.company,
230→      description_snippet: "description_snippet" in job ? (job as ScanResult).description_snippet : undefined,
231→    },
232→  });
233→
234→  // Dry-run: log complexity analysis and return early
235→  if (dryRun && submitResult.complexityAnalysis) {
236→    const ca = submitResult.complexityAnalysis;
237→    console.log(`\n  📊 Form Complexity Analysis:`);
238→    console.log(`     Fields: ${ca.totalFields} total, ${ca.requiredFields} required`);
239→    console.log(`     Resume upload: ${ca.hasResumeUpload ? "yes" : "no"}`);
240→    console.log(`     ATS type: ${ca.atsType}`);
241→    console.log(`     Multi-step: ${ca.isMultiStep ? "yes" : "no"}`);
242→    console.log(`     Difficulty: ${ca.estimatedDifficulty}`);
243→    console.log(`     Resume: ${resume.key} (${resume.filename})\n`);
244→    return {
245→      success: true,
246→      reason: submitResult.reason,
247→      application: record,
248→    };
249→  }
250→
251→  // Resolve "Unknown" metadata using browser-extracted page title data
252→  if (submitResult.extractedMetadata) {
253→    const meta = submitResult.extractedMetadata;
254→    if (record.company === "Unknown Company" && meta.company) {
255→      record.company = meta.company;
256→    }
257→    if (record.title === "Unknown Role" && meta.title) {
258→      record.title = meta.title;
259→    }
260→    // Recompute dedup hash with resolved metadata
261→    if (meta.company || meta.title) {
262→      record.dedup_hash = computeDedupHash(record.company, record.title, location);
263→    }
264→  }
265→
266→  if (submitResult.success) {
267→    record.status = "submitted";
268→    record.confirmation_detected = submitResult.confirmationDetected ?? false;
269→    record.notes = submitResult.reason ?? `Submitted via ${submitResult.atsType}`;
270→  } else {
271→    record.status = submitResult.status;
272→    record.confirmation_detected = false;
273→    record.notes = submitResult.reason ?? "Browser submission failed";
274→    // Mark CAPTCHA failures as non-retryable (dedup will block future attempts)
275→    if (submitResult.reason?.includes("CAPTCHA")) {
276→      record.notes = `[CAPTCHA_BLOCKED] ${submitResult.reason}`;
277→    }
278→    // Track problematic ATS domains by failure type (skip aggregator domains)
279→    if (shouldRecordAtsFailure(job.url)) {
280→      const reason = submitResult.reason?.toLowerCase() ?? "";
281→      if (reason.includes("captcha")) {
282→        await recordAtsFailure(job.url, "captcha");
283→      } else if (reason.includes("cloudflare") || reason.includes("challenge")) {
284→        await recordAtsFailure(job.url, "cloudflare");
285→      } else if (reason.includes("auth") || reason.includes("login")) {
286→        await recordAtsFailure(job.url, "auth_wall");
287→      } else if (submitResult.status === "incomplete_form") {
288→        await recordAtsFailure(job.url, "incomplete_form");
289→      }
290→    }
291→  }
292→
293→  try {
294→    await logApplication(record); // ISC #1, #16: awaited write to applications.jsonl
295→    return {
296→      success: submitResult.success,
297→      reason: submitResult.reason,
298→      application: record,
299→    };
300→  } catch (err) {
301→    return {
302→      success: false,
303→      reason: `Failed to log application: ${err instanceof Error ? err.message : err}`,
304→    };
305→  }
306→}
307→
308→// ─── Commands ─────────────────────────────────────────────────────────────────
309→
310→// ─── Queue Filtering & Sorting ─────────────────────────────────────────────
311→// Title exclusion and staleness filtering happen at scan time in JobScanner.ts.
312→// Location is RE-VALIDATED here against current profile preferences because
313→// scan results may pre-date location filter changes.
314→
315→function filterApplyQueue(queue: ScanResult[], profile: MasterProfile): ScanResult[] {
316→  const remoteOnly = profile.profile.remote_preference?.toLowerCase().includes("remote") ?? false;
317→  const acceptedCities = ["san diego"];
318→
319→  return queue
320→    .filter((r) => {
321→      const loc = (r.location ?? "").toLowerCase();
322→      const isRemote = loc.includes("remote") || loc.includes("anywhere") ||
323→        loc.includes("distributed") || loc.includes("work from home");
324→      if (isRemote) return true;
325→      if (remoteOnly) return false;
326→      if (loc.includes("hybrid")) return true;
327→      return acceptedCities.some((city) => loc.includes(city));
328→    })
329→    .sort((a, b) => b.match_score - a.match_score);
330→}
