332→async function commandApply(
333→  url: string | undefined,
334→  dryRun: boolean,
335→  jsonOutput: boolean,
336→  headless: boolean,
337→  limit?: number,
338→  sourceFilter?: string,
339→  verbose = false,
340→  force = false
341→): Promise<void> {
342→  let profile: MasterProfile;
343→  let targetCompanies: TargetCompanies;
344→
345→  try {
346→    profile = await loadMasterProfile(); // ISC #17: single source of truth
347→  } catch (err) {
348→    console.error(`FATAL: Cannot load master-profile.yaml: ${err instanceof Error ? err.message : err}`);
349→    process.exit(1);
350→  }
351→
352→  try {
353→    targetCompanies = await loadTargetCompanies(); // ISC #2, #15: yaml-helper
354→  } catch (err) {
355→    console.error(`FATAL: Cannot load target-companies.yaml: ${err instanceof Error ? err.message : err}`);
356→    process.exit(1);
357→  }
358→
359→  // ISC #13: Check daily cap
360→  const dailyCap = targetCompanies.settings.auto_apply_daily_cap ?? 15;
361→  const appliedToday = countApplicationsToday("auto-apply");
362→
363→  if (appliedToday >= dailyCap) {
364→    if (jsonOutput) {
365→      console.log(JSON.stringify({ error: "daily_cap_reached", applied_today: appliedToday, cap: dailyCap }));
366→    } else {
367→      console.error(`Daily auto-apply cap reached (${appliedToday}/${dailyCap}). Try again tomorrow.`);
368→    }
369→    process.exit(1);
370→  }
371→
372→  // ISC #13: Check weekly tailored cap
373→  const weeklyTailoredCap = targetCompanies.settings.weekly_cap ?? 5;
374→  const tailoredThisWeek = countTailoredApplicationsThisWeek();
375→  // (Weekly cap applies to tailored workflow, not auto-apply — but we still log for visibility)
376→
377→  // Build apply queue from scan-results (all filtering already done at scan time)
378→  const scanResults = readLatestScanResults();
379→  const rawQueue = scanResults.filter((r) => {
380→    if (r.tier !== "apply" || r.filter_status !== "pass") return false;
381→    if (sourceFilter && r.source !== sourceFilter) return false;
382→    return true;
383→  });
384→  const applyQueue = filterApplyQueue(rawQueue, profile);
385→
386→  // Determine batch size: --limit flag, daily cap remaining, or queue size
387→  const maxBatch = Math.min(limit ?? Infinity, dailyCap - appliedToday, applyQueue.length);
388→
389→  // If specific URL provided, skip queue and create a synthetic job.
390→  // Try to resolve metadata from scan results first, then from URL patterns.
391→  if (!jsonOutput && verbose) {
392→    console.log(`Auto-apply starting: ${appliedToday}/${dailyCap} applied today, cap remaining: ${dailyCap - appliedToday}`);
393→  }
394→
395→  let jobsToApply: Array<ScanResult | { title: string; company: string; url: string; match_score: number; location: string }>;
396→  if (url) {
397→    const existingScan = scanResults.find((r) => r.url === url);
398→    if (existingScan) {
399→      jobsToApply = [existingScan];
400→    } else {
401→      const urlMeta = extractMetadataFromUrl(url);
402→      jobsToApply = [{
403→        title: urlMeta.title ?? "Unknown Role",
404→        company: urlMeta.company ?? "Unknown Company",
405→        url,
406→        match_score: 0,
407→        location: "Remote",
408→      }];
409→    }
410→  } else {
411→    jobsToApply = applyQueue.slice(0, maxBatch);
412→  }
413→
414→  if (jobsToApply.length === 0) {
415→    if (jsonOutput) {
416→      console.log(JSON.stringify({ message: "No jobs in auto-apply queue", queue_size: applyQueue.length }));
417→    } else {
418→      console.log("No jobs in auto-apply queue.");
419→    }
420→    return;
421→  }
422→
423→  const results: Array<{
424→    company: string;
425→    title: string;
426→    success: boolean;
427→    reason?: string;
428→    variant?: string;
429→  }> = [];
430→
431→  const appliedUrlsThisBatch = new Set<string>();
432→
433→  for (const job of jobsToApply) {
434→    // Batch-level URL dedup: skip if same URL already attempted in this batch
435→    const normalizedUrl = job.url.toLowerCase().replace(/\/+$/, "");
436→    if (appliedUrlsThisBatch.has(normalizedUrl)) {
437→      results.push({
438→        company: job.company,
439→        title: job.title,
440→        success: false,
441→        reason: "Duplicate URL within batch",
442→      });
443→      if (!jsonOutput) {
444→        process.stdout.write(`  ⏭️ ${job.company} — ${job.title} (Duplicate URL within batch)\n`);
445→      }
446→      continue;
447→    }
448→
449→    // Inner submitApplication has its own timeouts: 10-min hard cap + 180s stall detection.
450→    // No outer timeout needed — it caused silent crashes by abandoning applyToJob mid-loop.
451→    let result: { success: boolean; reason?: string; application?: ApplicationRecord };
452→    try {
453→      result = await applyToJob(job, profile, targetCompanies, dryRun, headless, verbose, force);
454→    } catch (err) {
455→      const reason = err instanceof Error ? err.message : String(err);
456→      result = { success: false, reason };
457→      // Track failed ATS domains (skip aggregator domains like indeed.com)
458→      if (shouldRecordAtsFailure(job.url)) {
459→        await recordAtsFailure(job.url, "timeout");
460→      }
461→    }
462→    appliedUrlsThisBatch.add(normalizedUrl);
463→
464→    results.push({
465→      company: job.company,
466→      title: job.title,
467→      success: result.success,
468→      reason: result.reason,
469→      variant: result.application?.resume_variant,
470→    });
471→
472→    if (!jsonOutput) {
473→      const prefix = result.success ? "  ✅" : "  ❌";
474→      process.stdout.write(`${prefix} ${job.company} — ${job.title}${result.reason ? ` (${result.reason})` : ""}\n`);
475→    }
476→  }
477→
478→  const applied = results.filter((r) => r.success).length;
479→  const failed = results.filter((r) => !r.success).length;
480→
481→  if (jsonOutput) {
482→    console.log(JSON.stringify({
483→      applied,
484→      failed,
485→      dry_run: dryRun,
486→      daily_cap: dailyCap,
487→      applied_today: appliedToday + applied,
488→      weekly_tailored_remaining: weeklyTailoredCap - tailoredThisWeek,
489→      results,
490→    }));
491→    return;
492→  }
493→
494→  const summary = [
495→    `\nAuto-apply complete${dryRun ? " (dry-run)" : ""}:`,
496→    `  Applied:  ${applied}`,
497→    `  Failed:   ${failed}`,
498→    `  Today:    ${appliedToday + applied} / ${dailyCap}`,
499→  ].join("\n");
500→  // Use process.stdout.write to ensure output isn't swallowed by Bun's buffering in non-TTY mode
501→  process.stdout.write(summary + "\n");
502→}
