 87→/**
 88→ * Select the best resume PDF path for a given job title.
 89→ * Matches against the `roles` list in each resume config.
 90→ * Falls back to first available resume.
 91→ * Applies performance-based override if a higher-performing variant is available.
 92→ */
 93→export async function selectResumePath(
 94→  jobTitle: string,
 95→  profile: ProfileInfo
 96→): Promise<{ path: string; filename: string; key: string; performanceOverride?: boolean } | null> {
 97→  const resumes = profile.resumes;
 98→  if (!resumes) return null;
 99→
100→  const titleLower = jobTitle.toLowerCase();
101→
102→  // Determine the title-matched result (without returning yet)
103→  let result: { path: string; filename: string; key: string } | null = null;
104→
105→  // Try to match job title against each resume's roles list
106→  for (const [key, config] of Object.entries(resumes)) {
107→    if (!config?.roles) continue;
108→    const match = config.roles.some((role) =>
109→      titleLower.includes(role.toLowerCase()) || role.toLowerCase().includes(titleLower)
110→    );
111→    if (match) {
112→      result = { path: config.path, filename: config.filename, key };
113→      break;
114→    }
115→  }
116→
117→  // Fall back to first available
118→  if (!result) {
119→    const firstKey = Object.keys(resumes)[0];
120→    if (firstKey && resumes[firstKey]) {
121→      const config = resumes[firstKey]!;
122→      result = { path: config.path, filename: config.filename, key: firstKey };
123→    }
124→  }
125→
126→  // Performance-based override: prefer higher-performing variants
127→  try {
128→    const { computeVariantPerformance } = await import("../AnalyticsEngine.ts");
129→    const variants = computeVariantPerformance();
130→    if (variants.length >= 2 && result) {
131→      const currentVariant = variants.find(v => v.variant === result!.key);
132→      const bestVariant = variants.sort((a, b) => b.callback_rate - a.callback_rate)[0];
133→      if (currentVariant && currentVariant.callback_rate < 0.05 && bestVariant && bestVariant.callback_rate > 0.15) {
134→        const betterResume = resumes[bestVariant.variant];
135→        if (betterResume) {
136→          return { path: betterResume.path, filename: betterResume.filename, key: bestVariant.variant, performanceOverride: true };
137→        }
138→      }
139→    }
140→  } catch { /* Non-fatal */ }
141→
142→  return result;
143→}
